// src/pages/Attendance/ShiftsPage.js
import React, { useState, useEffect } from 'react';
import { attendanceAPI, employeeAPI } from '../../api/services';
import { Badge, SkeletonTable, InlineSpinner, Modal } from '../../components/common';
import { useAuth } from '../../context/AuthContext';
import { Layers, Plus } from 'lucide-react';
import toast from 'react-hot-toast';

export default function ShiftsPage() {
  const { user }    = useAuth();
  const isManager   = ['Manager','HR','Admin'].includes(user?.role || user?.Role);
  const [shifts,    setShifts]    = useState([]);
  const [employees, setEmployees] = useState([]);
  const [loading,   setLoading]   = useState(true);
  const [assignModal, setAssignModal] = useState(false);
  const [form,      setForm]      = useState({ EmployeeID: '', ShiftID: '', EffectiveFrom: '' });
  const [saving,    setSaving]    = useState(false);

  useEffect(() => {
    const unwrap = r => { const o = r?.data; return o && 'data' in o ? o.data : o; };
    Promise.all([
      attendanceAPI.listShifts(),
      isManager ? employeeAPI.list({ limit: 100 }) : Promise.resolve(null),
    ]).then(([s, e]) => {
      const sp = unwrap(s);
      setShifts(Array.isArray(sp) ? sp : sp?.shifts || []);
      if (e) {
        const ep = unwrap(e);
        setEmployees(Array.isArray(ep) ? ep : ep?.employees || []);
      }
      setLoading(false);
    }).catch(() => setLoading(false));
  }, [isManager]);

  const handleAssign = async () => {
    if (!form.EmployeeID || !form.ShiftID || !form.EffectiveFrom) {
      toast.error('All fields are required'); return;
    }
    setSaving(true);
    try {
      await attendanceAPI.assignShift({
        EmployeeID:    parseInt(form.EmployeeID),
        ShiftID:       parseInt(form.ShiftID),
        EffectiveFrom: form.EffectiveFrom,
        AssignedBy:    user?.id || user?.EmployeeID,
      });
      toast.success('Shift assigned successfully');
      setAssignModal(false);
      setForm({ EmployeeID: '', ShiftID: '', EffectiveFrom: '' });
    } catch (err) {
      toast.error(err.response?.data?.error?.message || 'Failed to assign shift');
    } finally { setSaving(false); }
  };

  const fmt = (t) => {
    if (!t) return '—';
    try { return new Date(`1970-01-01T${t.includes('T') ? t.split('T')[1].substring(0,5) : t}`).toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'}); }
    catch { return t; }
  };

  return (
    <>
      <div className="page-header-row">
        <div className="page-header" style={{ marginBottom: 0 }}>
          <h1>Shifts & Schedule</h1>
          <p>View available shifts and manage assignments</p>
        </div>
        {isManager && (
          <button className="btn btn-primary" onClick={() => setAssignModal(true)}>
            <Plus size={15} /> Assign Shift
          </button>
        )}
      </div>

      {loading ? <SkeletonTable rows={4} /> : (
        <div className="table-wrap" style={{ marginTop: 20 }}>
          <table>
            <thead>
              <tr><th>Shift Name</th><th>Code</th><th>Start</th><th>End</th><th>Expected Hours</th><th>Overnight</th><th>Night Shift</th></tr>
            </thead>
            <tbody>
              {shifts.length === 0 ? (
                <tr><td colSpan={7} style={{ textAlign: 'center', padding: 40, color: 'var(--text-muted)' }}>No shifts configured</td></tr>
              ) : shifts.map((s, i) => (
                <tr key={s.ShiftID || i}>
                  <td style={{ fontWeight: 500 }}>{s.ShiftName || s.shiftName || '—'}</td>
                  <td><span style={{ fontFamily: 'monospace', fontSize: '0.8rem', background: 'var(--bg-elevated)', padding: '2px 8px', borderRadius: 4 }}>{s.ShiftCode || s.shiftCode || '—'}</span></td>
                  <td>{fmt(s.StartTime || s.startTime)}</td>
                  <td>{fmt(s.EndTime   || s.endTime)}</td>
                  <td>{s.ExpectedHours || s.expectedHours || '—'}h</td>
                  <td><Badge status={s.IsOvernight || s.isOvernight ? 'Active' : 'Inactive'}>{s.IsOvernight || s.isOvernight ? 'Yes' : 'No'}</Badge></td>
                  <td><Badge status={s.IsNightShift || s.isNightShift ? 'Active' : 'Inactive'}>{s.IsNightShift || s.isNightShift ? 'Yes' : 'No'}</Badge></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Assign Shift Modal */}
      <Modal
        open={assignModal}
        onClose={() => setAssignModal(false)}
        title="Assign Shift to Employee"
        footer={
          <>
            <button className="btn btn-secondary" onClick={() => setAssignModal(false)} disabled={saving}>Cancel</button>
            <button className="btn btn-primary" onClick={handleAssign} disabled={saving}>
              {saving ? <InlineSpinner /> : 'Assign'}
            </button>
          </>
        }
      >
        <div className="form-group">
          <label className="form-label required">Employee</label>
          <select className="form-select" value={form.EmployeeID} onChange={e => setForm(f => ({ ...f, EmployeeID: e.target.value }))}>
            <option value="">Select employee...</option>
            {employees.map(emp => (
              <option key={emp.EmployeeID || emp.id} value={emp.EmployeeID || emp.id}>
                {emp.FullName || emp.fullName || `${emp.FirstName} ${emp.LastName}`}
              </option>
            ))}
          </select>
        </div>
        <div className="form-group">
          <label className="form-label required">Shift</label>
          <select className="form-select" value={form.ShiftID} onChange={e => setForm(f => ({ ...f, ShiftID: e.target.value }))}>
            <option value="">Select shift...</option>
            {shifts.map(s => (
              <option key={s.ShiftID} value={s.ShiftID}>{s.ShiftName}</option>
            ))}
          </select>
        </div>
        <div className="form-group">
          <label className="form-label required">Effective From</label>
          <input className="form-input" type="date" value={form.EffectiveFrom} onChange={e => setForm(f => ({ ...f, EffectiveFrom: e.target.value }))} />
        </div>
      </Modal>
    </>
  );
}
